import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './App.css';

function App() {
  // --- ESTADOS ---
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [usuario, setUsuario] = useState('');
  const [password, setPassword] = useState('');

  const [userRole, setUserRole] = useState(''); 
  const [view, setView] = useState('dashboard'); 
  const [stats, setStats] = useState({ total_productos: 0, valor_inventario: 0, bajo_stock: 0 });
  const [productos, setProductos] = useState([]);
  const [movimientos, setMovimientos] = useState([]);


  // NUEVOS ESTADOS PARA GESTIÓN
  const [showForm, setShowForm] = useState(false);
  const [editMode, setEditMode] = useState(false);
   const [selectedId, setSelectedId] = useState(null); // Mostrar/Ocultar formulario
  const [nuevoProd, setNuevoProd] = useState({
    nombre: '', categoria: '', stock: 0, precio_compra: 0, precio_venta: 0, fecha_caducidad: ''
  });

  // --- FUNCIONES DE CARGA (API) ---

  const cargarDatos = async () => {
    try {
      const resStats = await axios.get('http://localhost:5000/api/stats');
      setStats(resStats.data);

      const resProds = await axios.get('http://localhost:5000/api/productos');
      setProductos(resProds.data);
    } catch (error) {
      console.error("Error al cargar datos de SQL", error);
    }
  };

  useEffect(() => {
    if (isLoggedIn) {
      cargarDatos();
    }
  }, [isLoggedIn]);

  // --- MANEJADORES DE EVENTOS ---

  const handleLogin = async () => {
    try {
      const respuesta = await axios.post('http://localhost:5000/api/login', {
        usuario: usuario,
        clave: password
      });

      if (respuesta.data.success) {
        setIsLoggedIn(true);
        setUserRole(respuesta.data.rol);
      }
    } catch (error) {
      alert("Error: " + (error.response?.data?.message || "No se pudo conectar"));
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setView('dashboard');
    setUsuario('');
    setPassword('');
  };

  // Función para guardar producto en la base de datos
  const guardarProducto = async () => {
    try {
      const res = await axios.post('http://localhost:5000/api/productos', nuevoProd);
      if (res.data.success) {
        alert("¡Producto guardado exitosamente!");
        setShowForm(false); // Cerramos el formulario
        setNuevoProd({ nombre: '', categoria: '', stock: 0, precio_compra: 0, precio_venta: 0, fecha_caducidad: '' }); // Limpiamos campos
        cargarDatos(); // Recargamos la tabla y stats
      }
    } catch (error) {
      alert("Error al guardar el producto");
    }
  };

  // --- RENDERIZADO ---

  if (!isLoggedIn) {
    return (
      <div className="login-container">
        <div className="login-card">
          <h2>Iniciar Sesión</h2>
          <div className="form-group">
            <label>Usuario:</label>
            <input 
              type="text" 
              placeholder="eduardo" 
              value={usuario}
              onChange={(e) => setUsuario(e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Contraseña:</label>
            <input 
              type="password" 
              placeholder="••••••••••••" 
              value={password}
              onChange={(e) => setPassword(e.target.value)}
            />
          </div>
          <button className="btn-entrar" onClick={handleLogin}>Entrar</button>
          <button className="btn-registrar">Registrarse</button>
        </div>
      </div>
    );
  }

  return (
    <div>
      <header className="header">
        <h1 style={{ margin: 0, fontSize: '24px' }}>Mi Tiendita - {view === 'dashboard' ? 'Dashboard' : 'Gestión'}</h1>
        <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
          <span>Hola, <strong>{usuario}</strong> ({userRole})</span>
          <button className="btn-cerrar" onClick={handleLogout}>Cerrar Sesión</button>
        </div>
      </header>

      <nav className="nav-bar">
        <span className="nav-link" onClick={() => setView('dashboard')}>Inicio / Dashboard</span>
        {userRole === 'admin' && (
          <span className="nav-link" onClick={() => setView('gestion')}>Gestionar Productos</span>
        )}
        <span className="nav-link">Registrar Movimientos</span>
      </nav>

      <main style={{ padding: '20px' }}>
        {view === 'dashboard' ? (
          <div className="dashboard-grid">
            <div className="card">
              <h3>Productos con Bajo Stock</h3>
              <div className="card-content">
                {stats.bajo_stock > 0 
                  ? `¡Atención! Tienes ${stats.bajo_stock} productos con poco stock.` 
                  : "Todo en orden con el inventario."}
              </div>
            </div>

            <div className="card">
              <h3>Próximos a Caducar</h3>
              <div className="card-content">
                Verifica la pestaña de gestión para fechas.
              </div>
            </div>

            <div className="card">
              <h3>Resumen Diario</h3>
              <div className="card-content">Funcionalidad de ventas próximamente.</div>
            </div>

            <div className="card">
              <h3>Estadísticas Rápidas</h3>
              <div className="card-content">
                <p>Total de Productos: <strong>{stats.total_productos}</strong></p>
                <p>Valor del Inventario: <strong>${stats.valor_inventario}</strong></p>
              </div>
            </div>
          </div>
        ) : (
          <div className="card" style={{ width: '100%', boxSizing: 'border-box' }}>
            <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '20px', alignItems: 'center'}}>
               <h3>Listado de Inventario</h3>
               <button 
                className="btn-entrar" 
                style={{width: 'auto', padding: '10px 20px', background: showForm ? '#e74c3c' : '#2c97ad'}}
                onClick={() => setShowForm(!showForm)}
               >
                 {showForm ? 'Cancelar' : '+ Agregar Producto'}
               </button>
            </div>


            {/* FORMULARIO DE AGREGAR (Se muestra si showForm es true) */}
            {showForm && (
              <div style={{ background: '#f4f7f6', padding: '20px', borderRadius: '8px', marginBottom: '30px', border: '1px solid #ddd' }}>
                <h4 style={{marginTop: 0}}>Nuevo Producto</h4>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
                  <input className="input-form" type="text" placeholder="Nombre" onChange={(e) => setNuevoProd({...nuevoProd, nombre: e.target.value})} />
                  <input className="input-form" type="text" placeholder="Categoría" onChange={(e) => setNuevoProd({...nuevoProd, categoria: e.target.value})} />
                  <input className="input-form" type="number" placeholder="Stock Inicial" onChange={(e) => setNuevoProd({...nuevoProd, stock: e.target.value})} />
                  <input className="input-form" type="number" placeholder="Precio Compra" onChange={(e) => setNuevoProd({...nuevoProd, precio_compra: e.target.value})} />
                  <input className="input-form" type="number" placeholder="Precio Venta" onChange={(e) => setNuevoProd({...nuevoProd, precio_venta: e.target.value})} />
                  <input className="input-form" type="date" title="Fecha de Caducidad" onChange={(e) => setNuevoProd({...nuevoProd, fecha_caducidad: e.target.value})} />
                </div>
                <button className="btn-entrar" onClick={guardarProducto} style={{marginTop: '20px', width: '200px'}}>Guardar Producto</button>
              </div>
            )}


            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr style={{ borderBottom: '2px solid #eee', textAlign: 'left' }}>
                  <th style={{padding: '10px'}}>Nombre</th>
                  <th>Categoría</th>
                  <th>Stock</th>
                  <th>Precio Venta</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {productos.map(p => (
                  <tr key={p.id} className="table-row">
                    <td style={{ padding: '12px 10px' }}>{p.nombre}</td>
                    <td>{p.categoria}</td>
                    <td>{p.stock}</td>
                    <td>${p.precio_venta}</td>
                    <td>
                      <button className="btn-edit">Editar</button>
                      <button className="btn-delete">Eliminar</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </main>
    </div>
  );
}


export default App;
